// Función helper para obtener el contenido de forma segura
// Si el nodo falló o no tiene datos, devuelve un string vacío para no romper el flujo
const getWikiContent = (nodeName) => {
  try {
    const node = $(nodeName).first();
    return node ? node.json.content : "";
  } catch (error) {
    return "";
  }
};

// --- EXTRAER DATOS LIMPIOS ---

// 1. Obtenemos el texto Markdown de las Wikis
const release_planning = getWikiContent('1. Cargar el documento release planning');
const product_backlog = getWikiContent('2. Cargar el documento product backlog (Refinado, estimado y priorizado)');


// --- RETORNAR OBJETO UNIFICADO ---
return [{
  json: {
    // Metadatos para tu control
    fecha_proceso: new Date().toISOString(),

    // Contexto de Texto combinando todo o separado por claves
    contexto_release_planning: release_planning,
    contexto_product_backlog: product_backlog,
  }
}];

// ============================================================
// CÁLCULO DE CAPACIDAD (HÍBRIDO)
// ============================================================
const input = $input.first().json;

// 1. DEFINIR EQUIPO (Agente vs Default)
let equipo = input.equipo_config;

if (!equipo || !Array.isArray(equipo) || equipo.length === 0) {
    // DEFAULT (Si el agente no mandó nada)
    equipo = [
      { nombre: "David",     dias_disponibles: 11, dias_scrum: 7, horas_min: 2, horas_max: 3 },
      { nombre: "Emilio",    dias_disponibles: 11, dias_scrum: 5, horas_min: 3, horas_max: 4 },
      { nombre: "José",      dias_disponibles: 11, dias_scrum: 5, horas_min: 3, horas_max: 4 },
      { nombre: "Sebastián",      dias_disponibles: 11, dias_scrum: 8, horas_min: 2, horas_max: 3 },
      { nombre: "Estefano",      dias_disponibles: 11, dias_scrum: 6, horas_min: 1, horas_max: 2 },
      { nombre: "Anthony",      dias_disponibles: 11, dias_scrum: 5, horas_min: 1, horas_max: 2 },
    ];
}

// 2. CÁLCULO ESTRICTO
let granTotalMin = 0;
let granTotalMax = 0;

const equipoFormateado = equipo.map(m => {
  const diasNetos = Math.max(0, m.dias_disponibles - m.dias_scrum);
  const esfuerzoMin = diasNetos * m.horas_min;
  const esfuerzoMax = diasNetos * m.horas_max;

  granTotalMin += esfuerzoMin;
  granTotalMax += esfuerzoMax;

  return {
    persona: m.nombre,
    columna_dias_disponibles: m.dias_disponibles,
    columna_dias_scrum: m.dias_scrum,
    columna_horas_dia: `${m.horas_min} a ${m.horas_max}`,
    columna_esfuerzo: `${esfuerzoMin} a ${esfuerzoMax}`
  };
});

// 3. RETORNO
return [{
    json: {
      tabla_capacidad: equipoFormateado,
      resumen_total: {
        rango_total_texto: `${granTotalMin} a ${granTotalMax}`,
        min_horas: granTotalMin,
        max_horas: granTotalMax
      }
    }
}];

